const updatedProducts = $('Filter: Inventory Mismatch?').all();
const now = new Date();
const JACK_ID = 'U022BUNHE1Z';

// Categorize by severity
const critical = [];
const normal = [];

for (const p of updatedProducts) {
  const oldVal = p.json.inventory;
  const newVal = Math.round(Number(p.json.available_quantity));
  const diff = newVal - oldVal;
  const pctChange = oldVal > 0 ? Math.round(Math.abs(diff) / oldVal * 100) : (newVal !== 0 ? Math.round(Math.abs(diff) / Math.abs(newVal) * 100) : 0);

  // Calculate staleness
  const updatedAt = p.json.updated_at ? new Date(p.json.updated_at) : null;
  const staleMinutes = updatedAt ? Math.round((now - updatedAt) / 60000) : null;
  let staleStr = '';
  if (staleMinutes !== null) {
    if (staleMinutes < 60) staleStr = `${staleMinutes}m ago`;
    else if (staleMinutes < 1440) staleStr = `${Math.round(staleMinutes / 60)}h ago`;
    else staleStr = `${Math.round(staleMinutes / 1440)}d ago`;
  }

  const entry = { pid: p.json.product_id, sku: p.json.sku, oldVal, newVal, diff, pctChange, staleStr, staleMinutes };
  if (pctChange > 50 || (oldVal > 50 && newVal < 50) || Math.abs(diff) > 100) {
    critical.push(entry);
  } else {
    normal.push(entry);
  }
}

// Determine if Jack needs to be alerted
// Alert condition: any product whose absolute inventory diff is over 100
// Staleness alone is not actionable — the workflow already corrects stale values
const bigDiff = [...critical, ...normal].filter(e => Math.abs(e.diff) > 100);
const needsAttention = bigDiff.length > 0;

const blocks = [
  {
    type: "header",
    text: { type: "plain_text", text: `Inventory Sync: ${updatedProducts.length} products corrected`, emoji: true }
  }
];

// Tag Jack if attention needed
if (needsAttention) {
  const reasons = [];
  reasons.push(`${bigDiff.length} change${bigDiff.length === 1 ? '' : 's'} over 100 units`);
  blocks.push({
    type: "section",
    text: { type: "mrkdwn", text: `:rotating_light: <@${JACK_ID}> — ${reasons.join(', ')}` }
  });
}

// Summary stats
const totalUp = updatedProducts.filter(p => Number(p.json.available_quantity) > p.json.inventory).length;
const totalDown = updatedProducts.length - totalUp;
blocks.push({
  type: "section",
  text: { type: "mrkdwn", text: `*Summary:* ${totalUp} increased, ${totalDown} decreased` }
});

// Critical changes first
if (critical.length > 0) {
  blocks.push({ type: "divider" });
  blocks.push({
    type: "section",
    text: { type: "mrkdwn", text: ":warning: *Significant changes:*" }
  });
  const critLines = critical.map(e => {
    const arrow = e.diff > 0 ? ':arrow_up:' : ':arrow_down:';
    return `${arrow} *${e.sku}* (${e.pid}): ${e.oldVal} → ${e.newVal} (${e.diff > 0 ? '+' : ''}${e.diff}, ${e.pctChange}% change${e.staleStr ? ', last sync ' + e.staleStr : ''})`;
  });
  blocks.push({ type: "section", text: { type: "mrkdwn", text: critLines.join('\n') } });
}

// Normal changes
if (normal.length > 0) {
  blocks.push({ type: "divider" });
  function chunkArray(arr, size) {
    const chunks = [];
    for (let i = 0; i < arr.length; i += size) chunks.push(arr.slice(i, i + size));
    return chunks;
  }
  const lines = normal.map(e => {
    const sign = e.diff > 0 ? '+' : '';
    return `• ${e.sku} (${e.pid}): ${e.oldVal} → ${e.newVal} (${sign}${e.diff}${e.staleStr ? ', ' + e.staleStr : ''})`;
  });
  const chunks = chunkArray(lines, 30);
  chunks.forEach(chunk => {
    blocks.push({ type: "section", text: { type: "mrkdwn", text: chunk.join('\n') } });
  });
}

blocks.push({
  type: "context",
  elements: [{ type: "mrkdwn", text: `_Ran at ${now.toISOString().slice(0,19)}Z | <https://n8n.sugarwish.com/workflow/Waf2sOm2Aj0nJAx4|View workflow>_` }]
});

return [{ json: { blocks } }];

const JACK_ID = 'U022BUNHE1Z';
const workflowId = 'Waf2sOm2Aj0nJAx4';
const workflowLink = `https://n8n.sugarwish.com/workflow/${workflowId}`;
const executionLink = $execution?.id 
  ? `https://n8n.sugarwish.com/execution/${$execution.id}` 
  : workflowLink;

// Try to get error details from the failed node
let errorDetail = '';
try {
  const errorItems = $('Laravel: Update odoo_inventory with Correct Value').all();
  if (errorItems.length > 0 && errorItems[0].json.error) {
    errorDetail = `\n*Error:* ${errorItems[0].json.error}`;
  }
} catch (e) {
  errorDetail = '';
}

const blocks = [
  {
    type: "header",
    text: { type: "plain_text", text: "Inventory Sync Failed", emoji: true }
  },
  {
    type: "section",
    text: { type: "mrkdwn", text: `:rotating_light: <@${JACK_ID}> Inventory sync workflow failed. Products may have stale inventory values until the next successful run.${errorDetail}` }
  },
  {
    type: "section",
    text: { type: "mrkdwn", text: `<${workflowLink}|View Workflow> | <${executionLink}|View Execution>` }
  },
  {
    type: "context",
    elements: [{ type: "mrkdwn", text: `_Failed at ${new Date().toISOString().slice(0,19)}Z_` }]
  }
];

return [{ json: { blocks } }];
